  // Helper: send push notification to a specific user by userId
  async function sendPushToUser(userId: number, payload: { title: string; body: string; url?: string; tag?: string }): Promise<void> {
    if (!isDatabaseAvailable()) return;
    try {
      const vapidPublicKey = process.env.VAPID_PUBLIC_KEY;
      const vapidPrivateKey = process.env.VAPID_PRIVATE_KEY;
      if (!vapidPublicKey || !vapidPrivateKey) return;
      const webpush = (await import('web-push')).default;
      webpush.setVapidDetails('mailto:vadoalmaximo76@gmail.com', vapidPublicKey, vapidPrivateKey);
      const subs = await db.select().from(pushSubscriptions).where(eq(pushSubscriptions.userId, userId));
      const jsonPayload = JSON.stringify(payload);
      for (const sub of subs) {
        try {
          await webpush.sendNotification({ endpoint: sub.endpoint, keys: { p256dh: sub.p256dh, auth: sub.auth } }, jsonPayload);
          console.log(`[Push] Sent to user ${userId}: ${payload.title}`);
        } catch (e: any) {
          console.error(`[Push] sendPushToUser(${userId}) error: status=${e.statusCode} body=${JSON.stringify(e.body || e.message)}`);
          if (e.statusCode === 410 || e.statusCode === 404) {
            await db.delete(pushSubscriptions).where(eq(pushSubscriptions.endpoint, sub.endpoint));
          }
        }
      }
    } catch (e) {
      console.error('[Push] sendPushToUser error:', e);
    }
  }

  // ── Unified Notification Inbox helper ────────────────────────────────────────
  async function createNotification(
    userId: number,
    type: string,
    title: string,
    body: string,
    data: Record<string, any> = {},
    sendPush = true
  ): Promise<void> {
    if (!isDatabaseAvailable()) return;
    try {
      const [inserted] = await db.insert(notifications).values({ userId, type, title, body, data, isRead: false }).returning();
      console.log(`[Notification] Created for userId ${userId}: [${type}] ${title}`);

      // Real-time socket delivery to all active sessions of this user (multi-tab/device)
      try {
        const sockets = await io.fetchSockets();
        for (const s of sockets) {
          if ((s as any).data?.userId === userId) {
            s.emit('notification:new', inserted);
          }
        }
      } catch {}

      if (sendPush) {
        sendPushToUser(userId, { title, body, url: data.url, tag: data.tag }).catch(() => {});
      }
    } catch (e) {
      console.error('[Notification] createNotification error:', e);
    }
  }

