  // POST /api/draft/missions/templates - admin: create a new mission template
  app.post('/api/draft/missions/templates', authMiddleware, async (req, res) => {
    try {
      const user = (req as any).user;
      const isAdmin = await checkAdminAccess({ userId: user.userId, email: user.email });
      if (!isAdmin) return res.status(403).json({ error: 'Non autorizzato' });
      const { code, name, description, rewardCredits, requirement, icon, progressKey } = req.body;

      const VALID_PROGRESS_KEYS = ['packCount', 'deckComplete', 'epicCount', 'dailyCount'];
      if (!code || !name || !progressKey) return res.status(400).json({ error: 'code, name e progressKey sono obbligatori' });
      const sanitizedCode = String(code).toLowerCase().replace(/[^a-z0-9_]/g, '_').slice(0, 40);
      if (!sanitizedCode) return res.status(400).json({ error: 'Codice non valido' });
      if (!VALID_PROGRESS_KEYS.includes(progressKey)) return res.status(400).json({ error: `progressKey deve essere uno tra: ${VALID_PROGRESS_KEYS.join(', ')}` });

      const missions = getDraftMissions();
      if (missions.some(m => m.code === sanitizedCode)) return res.status(409).json({ error: 'Esiste già una missione con questo codice' });

      const newMission = {
        code: sanitizedCode,
        name: String(name).slice(0, 60),
        description: String(description || '').slice(0, 120),
        rewardCredits: Math.max(1, Math.min(9999, Number(rewardCredits) || 100)),
        requirement: Math.max(1, Math.min(999, Number(requirement) || 1)),
        icon: String(icon || '🎯').slice(0, 4),
        progressKey: String(progressKey),
      };
      missions.push(newMission);
      saveDraftMissions(missions);
      res.status(201).json(newMission);
    } catch (error) {
      res.status(500).json({ error: 'Errore creazione missione' });
    }
  });

  // GET /api/draft/cards - all cards with their draft costs
  app.get('/api/draft/cards', async (req, res) => {
    try {
      // Use jsonStorage as primary source (same as admin panel)
      const modifications = jsonStorage.cardModifications.getAll();
      const modMap = new Map(modifications.map((m: any) => [m.originalCardId, m]));

      const cards: any[] = [];
      const deckTypes = ['personaggi', 'mosse', 'bonus'] as const;

      // 1. Base game cards
      for (const deckType of deckTypes) {
        const deckUrls: string[] = (CARD_DATA as any)[deckType] || [];
        deckUrls.forEach((imageUrl: string, index: number) => {
          const cardId = `${deckType}-${index}`;
          const mod = modMap.get(cardId);

          if (mod?.isDeleted) return;

          // Extract display name from URL filename
          const urlParts = imageUrl.split('/');
          const filename = urlParts[urlParts.length - 1];
          const defaultName = decodeURIComponent(filename)
            .replace(/\.(png|jpg|jpeg|gif|webp)$/i, '')
            .replace(/[-_]/g, ' ')
            .trim();

          let basePti: number | null = mod?.pti ?? null;
          let baseStars: number | null = mod?.stars ?? null;
          if (deckType === 'personaggi' && (basePti == null || baseStars == null)) {
            const cardName = mod?.name || defaultName;
            const cached = getPersonaggioFromCache(cardName);
            if (cached) {
              if (basePti == null) basePti = cached.pti ?? null;
              if (baseStars == null) baseStars = cached.stars ?? null;
            }
          }
          cards.push({
            id: cardId,
            deckType,
            name: mod?.name || defaultName,
            imageUrl: mod?.imageUrl || imageUrl,
            pti: basePti,
            stars: baseStars,
            draftCost: (mod as any)?.draftCost ?? 0,
          });
        });
      }

      // 2. Permanently created custom cards (personaggi/mosse/bonus only)
      const allCustomCards = jsonStorage.customCards.getAll();
      for (const cc of allCustomCards as any[]) {
        if (!['personaggi', 'mosse', 'bonus'].includes(cc.deckType)) continue;
        cards.push({
          id: `custom-${cc.id}`,
          deckType: cc.deckType,
          name: cc.name,
          imageUrl: cc.imageData, // base64 or URL
          pti: cc.pti ?? null,
          stars: cc.stars ?? null,
          draftCost: cc.draftCost ?? 0,
          isCustom: true,
        });
      }

      res.json(cards);
    } catch (error) {
      console.error('Error fetching draft cards:', error);
      res.status(500).json({ error: 'Errore nel recupero carte draft' });
    }
  });

  // GET /api/draft/my-purchases - get user's own purchase history
