  // POST /api/draft/open-pack - buy and open a pack
  app.post('/api/draft/open-pack', authMiddleware, async (req, res) => {
    try {
      if (!isDatabaseAvailable()) return res.status(503).json({ error: 'DB non disponibile' });
      const user = (req as any).user;
      const [currentUser] = await db.select().from(users).where(eq(users.email, user.email)).limit(1);
      if (!currentUser) return res.status(404).json({ error: 'User not found' });

      const { packId } = req.body;
      const pack = getPackTypes().find((p: any) => p.id === packId);
      if (!pack) return res.status(400).json({ error: 'Pacchetto non valido' });

      const credits = await getOrCreateDraftCredits(currentUser.id);
      const totalAvailable = credits.freeCredits + credits.paidCredits + currentUser.puntiRankiard;
      if (totalAvailable < pack.creditsRequired) {
        return res.status(400).json({ error: `Crediti insufficienti. Servono ${pack.creditsRequired} crediti.` });
      }

      // Build card pool by rarity
      const cardPool = buildCardPoolByRarity();

      // Pick random cards for each slot, avoiding duplicates within the pack
      const usedCardIds = new Set<string>();
      const pickedCards: Array<{ cardId: string; deckType: string; rarity: string; frontImage: string; name: string; draftCost: number; pti?: number; stars?: number }> = [];

      for (const slot of (pack as any).slots) {
        let slotRarity: string;
        if (slot.alternatives && slot.alternatives.length > 0) {
          const totalWeight = slot.alternatives.reduce((s: number, a: any) => s + (a.weight || 1), 0);
          let rand = Math.random() * totalWeight;
          slotRarity = slot.alternatives[0].rarity;
          for (const alt of slot.alternatives) {
            rand -= alt.weight;
            if (rand <= 0) { slotRarity = alt.rarity; break; }
          }
        } else {
          slotRarity = slot.rarity || 'comune';
        }
        const slotDeckType: string | undefined = (slot as any).deckType;
        const basePool = cardPool[slotRarity] || cardPool['comune'];
        const filteredPool = slotDeckType ? basePool.filter((c: any) => c.deckType === slotDeckType) : basePool;
        const pool = filteredPool.length > 0 ? filteredPool : basePool;
        const available = pool.filter((c: any) => !usedCardIds.has(c.cardId));
        if (available.length === 0) {
          const fallback = (slotDeckType
            ? Object.values(cardPool).flat().filter((c: any) => c.deckType === slotDeckType)
            : Object.values(cardPool).flat()
          ).filter((c: any) => !usedCardIds.has(c.cardId));
          if (fallback.length === 0) continue;
          const chosen = fallback[Math.floor(Math.random() * fallback.length)] as any;
          usedCardIds.add(chosen.cardId);
          pickedCards.push({ ...chosen, rarity: slotRarity });
        } else {
          const chosen = available[Math.floor(Math.random() * available.length)];
          usedCardIds.add(chosen.cardId);
          pickedCards.push({ ...chosen, rarity: slotRarity });
        }
      }

      // Deduct credits: use paidCredits first, then freeCredits
      let remaining = pack.creditsRequired;
      let newPaid = credits.paidCredits;
      let newFree = credits.freeCredits;
      let rankiardDeducted = 0;
      if (newPaid >= remaining) {
        newPaid -= remaining;
        remaining = 0;
      } else {
        remaining -= newPaid;
        newPaid = 0;
        if (newFree >= remaining) {
          newFree -= remaining;
          remaining = 0;
        } else {
          remaining -= newFree;
          newFree = 0;
          rankiardDeducted = remaining;
        }
      }
      await db.update(userDraftCredits).set({ paidCredits: newPaid, freeCredits: newFree, updatedAt: new Date() })
        .where(eq(userDraftCredits.userId, currentUser.id));
      if (rankiardDeducted > 0) {
        await db.update(users).set({ puntiRankiard: Math.max(0, currentUser.puntiRankiard - rankiardDeducted) })
          .where(eq(users.id, currentUser.id));
      }

      // Fetch user's active deck and presets for deck-based duplicate detection
      const [activeDeckRow] = await db.select().from(draftDecks).where(eq(draftDecks.userId, currentUser.id)).limit(1);
      const userPresetRows = await db.select().from(draftDeckPresets).where(eq(draftDeckPresets.userId, currentUser.id));

      const deckHasCardFn = (deck: { personaggiCards: unknown; mosseCards: unknown; bonusCards: unknown }, cardId: string, deckType: string): boolean => {
        let arr: string[] = [];
        if (deckType === 'personaggi' || deckType === 'personaggi_speciali') arr = (deck.personaggiCards as string[]) || [];
        else if (deckType === 'mosse') arr = (deck.mosseCards as string[]) || [];
        else if (deckType === 'bonus') arr = (deck.bonusCards as string[]) || [];
        return arr.includes(cardId);
      };

      // Add all cards to collection (record possession, ignore conflicts)
      for (const card of pickedCards) {
        try {
          await db.insert(userCardCollection).values({
            userId: currentUser.id,
            cardId: card.cardId,
            deckType: card.deckType,
            rarity: card.rarity,
          }).onConflictDoNothing();
        } catch (_) {}
      }

      // Build per-card deck presence info and mark duplicates at deck level
      const cardsWithDuplicateInfo = pickedCards.map(c => {
        const deckPresence: Array<{ deckId: number | null; deckName: string; hasCard: boolean }> = [];
        if (activeDeckRow) {
          deckPresence.push({ deckId: null, deckName: 'Mazzo attivo', hasCard: deckHasCardFn(activeDeckRow, c.cardId, c.deckType) });
        }
        for (const preset of userPresetRows) {
          deckPresence.push({ deckId: preset.id, deckName: preset.presetName, hasCard: deckHasCardFn(preset, c.cardId, c.deckType) });
        }
        const allDecksHaveCard = deckPresence.length > 0 && deckPresence.every(d => d.hasCard);
        const anyDeckHasCard = deckPresence.some(d => d.hasCard);
        const halfCost = Math.floor((c.draftCost || 0) / 2);
        return {
          ...c,
          isDuplicate: allDecksHaveCard,
          halfRefundCredits: anyDeckHasCard ? halfCost : 0,
          duplicateCredits: anyDeckHasCard ? halfCost : 0,
          deckPresence,
        };
      });

      // Record pack opening
      await db.insert(draftPackOpenings).values({
        userId: currentUser.id,
        packId,
        creditsSpent: pack.creditsRequired,
        cardsObtained: cardsWithDuplicateInfo,
        duplicatesCredits: 0,
      });

      res.json({ success: true, cards: cardsWithDuplicateInfo, duplicatesCreditsEarned: 0 });
    } catch (error: any) {
      console.error('Error opening pack:', error);
      res.status(500).json({ error: 'Errore nell\'apertura del pacchetto' });
    }
  });

